	}

	// Encode subject using MIME encoding to handle special characters and prevent header injection
	// RFC 2047 encoding ensures the subject is safe for email headers
	emailSubject := mime.QEncoding.Encode("UTF-8", fmt.Sprintf("Feedback: %s", subject))

