// containsNewline checks if a string contains CR or LF characters
func containsNewline(s string) bool {
	return strings.ContainsAny(s, "\r\n")
}

// sanitizeHeader removes CR and LF characters to prevent header injection
func sanitizeHeader(s string) string {
	return strings.NewReplacer("\r", "", "\n", "").Replace(s)
}

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format using mail.ParseAddress
	// This ensures proper RFC 5322 compliance
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Defense in depth: ensure formatted addresses don't contain newlines
	if containsNewline(from.String()) || containsNewline(to.String()) {
		return "", fmt.Errorf("email address contains invalid characters")
	}

	// Sanitize subject to prevent header injection by removing CR/LF
	sanitizedSubject := sanitizeHeader(subject)

	// Escape HTML in all user-provided content to prevent HTML injection/XSS
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(sanitizedSubject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct email headers with properly formatted addresses
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)

	// Build headers using properly formatted email addresses
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		from.String(),
		to.String(),
		emailSubject,
	)

	// Construct HTML body with escaped content to prevent injection
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
