//   - toAddr: recipient email address (customer support team)
//   - userName: the name of the user submitting feedback
//   - subject: the subject of the feedback
//   - feedbackContent: the detailed feedback content from the user
//
// Returns:
//   - emailBody: the complete email content including headers and HTML body
//   - err: error if any occurred during email construction
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Construct email headers following SMTP standards
	headers := map[string]string{
		"From":         fromAddr,
		"To":           toAddr,
		"Subject":      "User Feedback: " + subject,
		"MIME-Version": "1.0",
		"Content-Type": "text/html; charset=\"UTF-8\"",
	}

	// Build headers section using bytes.Buffer for efficient string concatenation
	var buffer bytes.Buffer
	for key, value := range headers {
		buffer.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	buffer.WriteString("\r\n")

	// Escape HTML special characters to prevent XSS and ensure proper rendering
