	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize subject to prevent header injection by removing CR/LF characters
	safeSubject := strings.ReplaceAll(subject, "\r", "")
	safeSubject = strings.ReplaceAll(safeSubject, "\n", "")

	// Construct email headers with sanitized values
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		parsedFrom.Address,
		parsedTo.Address,
		emailSubject,
	)

	// Escape all user-provided content to prevent XSS in HTML body
	safeUserName := html.EscapeString(userName)
	safeSubjectHTML := html.EscapeString(subject)
	safeFeedbackContent := html.EscapeString(feedbackContent)

	// Construct HTML body with escaped content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
