// BuildFeedbackEmail generates an HTML-formatted email body for user feedback.
// The returned emailBody is formatted according to SMTP standards and can be
// directly used with smtp.SendMail function.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Construct email headers following SMTP message format
	// Headers must use CRLF (\r\n) line endings as per RFC 5322
	headers := map[string]string{
		"From":         fromAddr,
		"To":           toAddr,
		"Subject":      "User Feedback: " + subject,
		"MIME-Version": "1.0",
		"Content-Type": `text/html; charset="UTF-8"`,
	}

	// Build headers string using CRLF line endings (SMTP standard)
	var buffer bytes.Buffer
	for key, value := range headers {
		buffer.WriteString(key)
		buffer.WriteString(": ")
		buffer.WriteString(value)
		buffer.WriteString("\r\n")
	}

	// Add blank line between headers and body (required by SMTP)
	buffer.WriteString("\r\n")

	// Construct HTML email body with user feedback information
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body {
            font-family: Arial, Helvetica, sans-serif;
            margin: 0;
            padding: 20px;
            background-color: #f4f4f4;
        }
        .container {
            max-width: 600px;
            margin: 0 auto;
            background: #ffffff;
