        .value { padding: 12px; background-color: #f9f9f9; border-left: 4px solid #4CAF50; white-space: pre-wrap; word-wrap: break-word; }
        .footer { margin-top: 20px; padding-top: 15px; border-top: 1px solid #eee; color: #888; font-size: 12px; }
