		message.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}
	message.WriteString("\r\n")
	message.WriteString(htmlContent)

	return message.String(), nil
}

// SendFeedbackEmail sends the feedback email using net/smtp
// This helper function demonstrates integration with the net/smtp package
func SendFeedbackEmail(smtpHost string, smtpPort string, auth smtp.Auth, fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {
	// Build the email body using BuildFeedbackEmail
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
	if err != nil {
		return fmt.Errorf("failed to build email: %w", err)
	}

	// Construct the SMTP server address
	addr := fmt.Sprintf("%s:%s", smtpHost, smtpPort)

	// Send the email using net/smtp.SendMail
	err = smtp.SendMail(addr, auth, fromAddr, []string{toAddr}, []byte(emailBody))
	if err != nil {
		return fmt.Errorf("failed to send email: %w", err)
	}

	return nil
}

