	if containsNewline(fromParsed.Address) || containsNewline(toParsed.Address) {
		return "", fmt.Errorf("email address contains invalid characters")
	}

	// Construct email subject with proper RFC 2047 encoding to prevent header injection
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mime.QEncoding.Encode("UTF-8", emailSubject)

	// Construct email headers with validated addresses
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromParsed.Address,
		toParsed.Address,
		encodedSubject,
	)

	// Escape HTML special characters to prevent XSS attacks
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedFeedbackContent := html.EscapeString(feedbackContent)

	// Construct HTML body with escaped content
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
