func SendFeedbackEmail(smtpHost string, smtpPort string, username string, password string, fromAddr string, toAddr string, userName string, subject string, feedbackContent string) error {
	emailBody, err := BuildFeedbackEmail(fromAddr, toAddr, userName, subject, feedbackContent)
